// // This module designs a 3-bit wide down-counter that decrements its value on every rising edge of the clock signal (clk). When the reset signal (rst) is high, the counter resets to seven.
module top_module(clk, rst, count);input clk, rst;
  output reg [2:0] count;

  always @(posedge clk) begin
    if (rst == 1) begin
      count <= 0;
    end else begin
      count <= count + 1;
    end
  end

endmodule
